VALUES
  ('diplomatic-8a96f9fb-moex-00352', 'diplomatic-8a96f9fb', 'diplomatic-8a96f9fb-moex-112-7f4830a9', 'sub-diplomatic-8a96f9fb-04', NULL, 'single_choice', '清朝簽訂的對外條約當中，那一個賠款最多？', '["伊犁條約", "辛丑條約", "馬關條約", "天津條約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:51+00:00", "source_pdf_sha1": "cb69610e8100", "answer_pdf_sha1": "f2cb8661297c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-俄文組"}'::jsonb, NULL),
  ('diplomatic-8a96f9fb-moex-00353', 'diplomatic-8a96f9fb', 'diplomatic-8a96f9fb-moex-112-7f4830a9', 'sub-diplomatic-8a96f9fb-04', NULL, 'single_choice', '有關清朝末年邊疆爭端的敘述，下列何者正確？', '["咸豐6年（1856年），回變最早起於雲南，其得到沙俄的外交支持，並以馬如龍、杜文秀勢力 最大", "咸豐8年（1858年），第一次英法聯軍進逼天津，沙俄將領莫拉維也夫（NikolayN.Muravyov） 乘機出兵璦琿，威逼李鴻章，簽訂《璦琿條約》", "同治3年（1864年）新疆回變，中亞浩罕國國王派部將阿古柏（MuhammadYaqubBek）東來， 建立回教汗國，最後由曾國藩西征討平", "新疆回變發生，沙俄軍隊於同治10年（1871年）佔據伊犂。清廷派遣駐英法大臣曾紀澤前往 聖彼得堡談判，始得爭回部分領土權益"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:51+00:00", "source_pdf_sha1": "cb69610e8100", "answer_pdf_sha1": "f2cb8661297c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-俄文組"}'::jsonb, NULL),
  ('diplomatic-8a96f9fb-moex-00354', 'diplomatic-8a96f9fb', 'diplomatic-8a96f9fb-moex-112-7f4830a9', 'sub-diplomatic-8a96f9fb-04', NULL, 'single_choice', '1899年美國國務卿海約翰（JohnHay）主張中國門戶開放政策，下列敘述何者錯誤？', '["美國在美西戰爭獲勝取得菲律賓後實力增強", "美國在中國商業利益逐漸增多", "美國主張各國門戶開放原是外交傳統", "美國以尊重列強在中國勢力範圍取得的特權爭取支持"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:51+00:00", "source_pdf_sha1": "cb69610e8100", "answer_pdf_sha1": "f2cb8661297c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-俄文組"}'::jsonb, NULL),
  ('diplomatic-8a96f9fb-moex-00355', 'diplomatic-8a96f9fb', 'diplomatic-8a96f9fb-moex-112-7f4830a9', 'sub-diplomatic-8a96f9fb-04', NULL, 'single_choice', '有關於第二次世界大戰期間，同盟國之間的合作，下列敘述何者正確？', '["民國26年（1937年）「七七事變」爆發，美、英為加強對華友誼，迅即撤銷不平等條約", "民國32年（1943年）11月，美國總統羅斯福（FranklinD.Roosevelt）、英國首相邱吉爾（Winston Churchill），邀請國民政府主席蔣中正前往開羅，並發表《開羅宣言》，同意戰後朝鮮獨立", "民國 33 年（1944 年）10 月，中華民國與美、英、法共同宣布《聯合國組織案》，成為「聯合 國」的創始會員國", "民國34年（1945年），希特勒（AdolfHitler）敗亡前，中、美、英3國發表《波茨坦宣言》，要 求德國無條件投降"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:51+00:00", "source_pdf_sha1": "cb69610e8100", "answer_pdf_sha1": "f2cb8661297c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-俄文組"}'::jsonb, NULL),
  ('diplomatic-8a96f9fb-moex-00356', 'diplomatic-8a96f9fb', 'diplomatic-8a96f9fb-moex-112-7f4830a9', 'sub-diplomatic-8a96f9fb-04', NULL, 'single_choice', '有關於美蘇冷戰在二戰結束後的發展，下列敘述何者正確？', '["美國總統杜魯門（HarryS.Truman）1946年3月5日在美國的演講中，率先使用「鐵幕」（Iron Curtain）一詞", "馬歇爾計劃（TheMarshallPlan）在1947年7月啟動，其援助範圍包括現今整個歐盟地區", "圍堵（Containment）政策係由肯楠（GeorgeF.Kennan）所建議，得到美國總統杜魯門的支持", "圍堵（Containment）政策下所組成的集體防衛機制中，目前繼續存在的有「東南亞公約組織」 （SEATO）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:51+00:00", "source_pdf_sha1": "cb69610e8100", "answer_pdf_sha1": "f2cb8661297c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-俄文組"}'::jsonb, NULL),
  ('diplomatic-8a96f9fb-moex-00357', 'diplomatic-8a96f9fb', 'diplomatic-8a96f9fb-moex-112-7f4830a9', 'sub-diplomatic-8a96f9fb-04', NULL, 'single_choice', '第一次世界大戰爆發的原因，下列敘述何者錯誤？', '["德國首相俾斯麥打造的同盟體系失控，因而導致戰爭", "德俄再保條約因俄國不願續約，德俄關係進一步惡化", "德國遂行「大海軍計畫」侵犯英國重大利益", "法俄同盟、英法協商、英俄協商接連實現，使德國面臨外交孤立"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:51+00:00", "source_pdf_sha1": "cb69610e8100", "answer_pdf_sha1": "f2cb8661297c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-俄文組"}'::jsonb, NULL),
  ('diplomatic-8a96f9fb-moex-00358', 'diplomatic-8a96f9fb', 'diplomatic-8a96f9fb-moex-112-c655adf3', 'sub-diplomatic-8a96f9fb-05', NULL, 'single_choice', '依司法院大法官解釋意旨，關於大學教師之升等評審程序，下列敘述何者正確？', '["基於大學自治，有關大學教師升等資格之審查，立法者不得為任何規定", "基於大學自治，對於升等決定不服之教師，不得提起行政訴訟", "大學教師升等資格之審查，涉及工作權之保障", "教師升等資格評審程序之目的在於維持學術研究與教學之品質，不受教育主管機關監督"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:52+00:00", "source_pdf_sha1": "666ca31ec295", "answer_pdf_sha1": "0b8d6d62dd21", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-俄文組"}'::jsonb, NULL),
  ('diplomatic-8a96f9fb-moex-00359', 'diplomatic-8a96f9fb', 'diplomatic-8a96f9fb-moex-112-c655adf3', 'sub-diplomatic-8a96f9fb-05', NULL, 'single_choice', '有關監察權之行使，下列敘述何者錯誤？', '["監察院僅得對行政院及其有關部會提出糾正案", "監察委員對行政院及各部會行使之調查權範圍，僅限於調閱文件", "監察院院長對於彈劾案不得指使與干涉", "監察院院長對於糾舉案不得指使與干涉"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:52+00:00", "source_pdf_sha1": "666ca31ec295", "answer_pdf_sha1": "0b8d6d62dd21", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-俄文組"}'::jsonb, NULL),
